import React, { Component } from 'react';
import axios from 'axios'
import './search.css'
import Grid from '../grid/grid'
import LoadMoreBtn from '../loadMore/loadMore'

const apikey = "37e7a5cb2b4f66257a0b6632a59060a5"

class Search extends Component{

    constructor(props){
        super(props)
		this.onChangeSearchValue = this.onChangeSearchValue.bind(this);
		this.onSubmit = this.onSubmit.bind(this);
        this.state={
            movies: [],
            searchTerm: "",
            currentPage: 1,
            loading: false,
            noResults: false,
            server: process.env.REACT_APP_SERVER_URL || ''
        }
    }

	onChangeSearchValue(e) {
		this.setState ({
			search_value: e.target.value
		});
	}

	async onSubmit(e) {
		e.preventDefault();

		var searchList = [];
		var searchValue = this.state.search_value

		console.log(`Search Made for: ${searchValue}`);

		await fetch("https://api.themoviedb.org/3/search/movie?api_key=" + apikey + "&language=en-US&query=" + searchValue + " &page="+ 1 + "&include_adult=false")
			.then(response=>response.json())
			.then(function(data) {
				if(data["status_code"]) {
					alert("error");
				}
				else
				{
					searchList = data.results;
				}
		});

		this.setState({
			search_value: '',
			search_results: searchList,
		});
	}


    preformSearch = (searchTerm, pageNum) =>{
        // https://developers.themoviedb.org/3/

        this.setState({noResults: false})
        this.setState({loading: true})
        const URL = "https://api.themoviedb.org/3/search/movie?api_key=" + apikey + "&language=en-US&query=" + searchValue + " &page="+ 1 + "&include_adult=false";//this.state.server+`/api/movies/search/${searchTerm}/${pageNum}`

        axios.get(URL)
		.then((response) => {
			this.setState({
				movies: response.data,
				pageNum: this.state.pageNum+1,
				loading: false
			})

			if (response.data.length === 0 && searchTerm !== ""){
				this.setState({noResults: true})
			}
		})
		.catch(err =>{
			console.log(err)
		});
    }

    appendSearch = (searchTerm, pageNum) =>{
        // https://developers.themoviedb.org/3/

        this.setState({noResults: false})
        this.setState({loading: true})

        const URL = this.state.server+`/api/movies/search/${searchTerm}/${pageNum}`

        axios.get(URL)
        .then((response) => {
            response.data.forEach(element => {
                this.state.movies.push(element)
            });
            this.setState({loading: false})

            if (response.data.length === 0 && searchTerm !== ""){
                this.setState({noResults: true})
            }
        })
        .catch(err =>{
            console.log(err)
        });
    }

    changeHandler = (event) => {
        this.setState({currentPage: 1, searchTerm: event.target.value}, ()=>{
            if(this.state.searchTerm !== ""){
                this.preformSearch(this.state.searchTerm, 1)
            }   
        })
    }

    clickHandler = () =>{
        this.setState({currentPage: this.state.currentPage+1}, () =>{
            this.appendSearch(this.state.searchTerm, this.state.currentPage)
        })
    }

    render() {
        if (this.state.noResults){
            return(
                <div className='form-group'>
					<input type="text" className="search" value={this.state.search_value} onChange={this.onChangeSearchValue} placeholder="Search for a movie" onSubmit={this.onSubmit}/>
                    <br/>
                    <Grid movies={this.state.movies}/>
                	<div className="alert alert-primary" role="alert">
                        No results found
                    </div>
                </div>  
            )
        }
        else{
            if (this.state.loading || this.state.searchTerm===""){
                return(
                    <div className='form-group'>
                        <input type="text" className="search" value={this.state.search_value} onChange={this.onChangeSearchValue} placeholder="Search for a movie" onSubmit={this.onSubmit}/>
                        <br/>
                        <Grid movies={this.state.movies}/>
                    </div>  
                );
            }
            else{
                return(
                    <div className='form-group'>
                        <input type="text" className="search" value={this.state.search_value} onChange={this.onChangeSearchValue} placeholder="Search for a movie" onSubmit={this.onSubmit}/>
                        <br/>
                        <Grid movies={this.state.movies}/>
                        <LoadMoreBtn text='Load More' onClick={this.clickHandler}/>
                    </div>  
                );
            }
        }  
    }
}

export default Search
